# src/lib/sort_json.sh
# Trier par ordre alphabétique
sort_json(){
    # Check if .JSON file is correct
    jq -e . $file > /dev/null

    if [[ $? -ne 0 ]]; then
        exit 1
    fi

    tmp=$(mktemp)

    jq '
    to_entries
    | map(. as $e
          | {
              e: $e,
              sortkey: ($e.key
                | gsub("é";"e")
                | gsub("è";"e")
                | gsub("ê";"e")
                | gsub("ë";"e")
                | gsub("à";"a")
                | gsub("â";"a")
                | gsub("ä";"a")
                | gsub("ç";"c")
                | gsub("î";"i")
                | gsub("ï";"i")
                | gsub("ô";"o")
                | gsub("ö";"o")
                | gsub("ù";"u")
                | gsub("û";"u")
                | gsub("ü";"u")
                | gsub("É";"E")
                | gsub("È";"E")
                | gsub("Ê";"E")
                | gsub("Ë";"E")
                | gsub("À";"A")
                | gsub("Â";"A")
                | gsub("Ä";"A")
                | gsub("Ç";"C")
                | gsub("Î";"I")
                | gsub("Ï";"I")
                | gsub("Ô";"O")
                | gsub("Ö";"O")
                | gsub("Ù";"U")
                | gsub("Û";"U")
                | gsub("Ü";"U")
              )
            })
    | sort_by(.sortkey, (.e.key))
    | map(.e)
    | from_entries
    ' "$file" > "$tmp"
    mv "$tmp" "$file"
}

# :command.command_functions

# :command.parse_requirements
parse_requirements() {
  local key

  # :command.fixed_flags_filter
  while [[ $# -gt 0 ]]; do
    key="$1"
    case "$key" in
      --version)
        version_command
        exit
        ;;

      --help | -h)
        long_usage=yes
        cvdq_cli_usage
        exit
        ;;

      *)
        break
        ;;

    esac
  done

  # :command.environment_variables_filter
  # :command.environment_variables_default
  export DEFAULT_GLOSSARY="${DEFAULT_GLOSSARY:-json/glossaire.json}"
  export REMOTE_SOURCE="${REMOTE_SOURCE:-https://data.occitanie.education.gouv.fr/api/explore/v2.1/catalog/datasets/fr-en-occitanie-glossaire-sigles-acronymes/exports/json}"

  env_var_names+=("DEFAULT_GLOSSARY")
  env_var_names+=("REMOTE_SOURCE")

  # :command.command_filter
  action="root"

  # :command.parse_requirements_while
  while [[ $# -gt 0 ]]; do
    key="$1"
    case "$key" in
      # :flag.case
      --add | -a)

        # :flag.case_arg
        if [[ -n ${2+x} ]]; then
          args['--add']="$2"
          shift
          shift
        else
          printf "%s\n" "--add requires an argument: --add, -a NEW_ITEM" >&2
          exit 1
        fi
        ;;

      # :flag.case
      --key | -k)

        # :flag.case_arg
        if [[ -n ${2+x} ]]; then
          args['--key']="$2"
          shift
          shift
        else
          printf "%s\n" "--key requires an argument: --key, -k KEY" >&2
          exit 1
        fi
        ;;

      # :flag.case
      --verbose | -v)

        # :flag.case_no_arg
        args['--verbose']=1
        shift
        ;;

      # :flag.case
      --item | -i)

        # :flag.case_arg
        if [[ -n ${2+x} ]]; then
          args['--item']="$2"
          shift
          shift
        else
          printf "%s\n" "--item requires an argument: --item, -i ITEM" >&2
          exit 1
        fi
        ;;

      # :flag.case
      --sort | -s)

        # :flag.case_no_arg
        args['--sort']=1
        shift
        ;;

      # :flag.case
      --format | -f)

        # :flag.case_no_arg
        args['--format']=1
        shift
        ;;

      # :flag.case
      --remote | -r)
        # :flag.conflicts
        for conflict in --sort --format --add; do
          if [[ -n "${args[$conflict]:-}" ]]; then
            printf "conflicting options: %s cannot be used with %s\n" "$key" "$conflict" >&2
            exit 1
          fi
        done

        # :flag.case_no_arg
        args['--remote']=1
        shift
        ;;

      -?*)
        printf "invalid option: %s\n" "$key" >&2
        exit 1
        ;;

      *)
        # :command.parse_requirements_case
        # :command.parse_requirements_case_simple
        # :argument.case
        if [[ -z ${args['FILE']+x} ]]; then
          args['FILE']=$1
          shift
        else
          printf "invalid argument: %s\n" "$key" >&2
          exit 1
        fi

        ;;

    esac
  done

  # :command.needy_flags_filter
  # :flag.needs
  if [[ -n ${args['--remote']+x} ]] && [[ -z "${args[--item]:-}" ]]; then
    printf "%s\n" "--remote needs --item" >&2
    exit 1
  fi

  # :command.default_assignments
  [[ -n ${args['--key']:-} ]] || args['--key']="desc"

}

# :command.initialize
initialize() {
  declare -g version="1.2.0"
  set -e

  # :command.environment_variables_default
  export DEFAULT_GLOSSARY="${DEFAULT_GLOSSARY:-json/glossaire.json}"
  export REMOTE_SOURCE="${REMOTE_SOURCE:-https://data.occitanie.education.gouv.fr/api/explore/v2.1/catalog/datasets/fr-en-occitanie-glossaire-sigles-acronymes/exports/json}"

}

# :command.run
run() {
  # :command.globals
  declare -g long_usage=''
  declare -g -A args=()
  declare -g -A deps=()
  declare -g -a env_var_names=()
  declare -g -a input=()

  normalize_input "$@"
  parse_requirements "${input[@]}"

  case "$action" in
    "root") root_command ;;
  esac
}

if [[ "${BASH_SOURCE[0]}" == "${0}" ]]; then
  # :command.start
  command_line_args=("$@")
  initialize
  run "${command_line_args[@]}"
fi
